import UserPage from 'flarum/forum/components/UserPage';
import MoneyHistoryList from './MoneyHistoryList';
export default class MoneyHistoryPage extends UserPage {
  oninit(vnode) {
    super.oninit(vnode);
    this.loadUser(m.route.param('username'));
  }
  content() {
    return m("div", {
      className: "MoneyHistoryPage-content"
    }, m(MoneyHistoryList, {
      params: {
        user: this.user
      }
    }));
  }
}
flarum.reg.add('huoxin-money-with-history', 'forum/components/MoneyHistoryPage', MoneyHistoryPage);